using System.ComponentModel;
using System.Text;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this sample.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Build the IChatClient via MEAI + OpenAI provider ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Define tools ---
var notebook = new ResearchNotebook();

var searchTool = AIFunctionFactory.Create(
    [Description("Searches the web for information on a query and returns result snippets.")]
    async (
        [Description("The search query to look up on the web")] string query,
        CancellationToken cancellationToken) =>
    {
        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  🔍 Searching: \"{query}\"");
        Console.ResetColor();

        using var http = new HttpClient { Timeout = TimeSpan.FromSeconds(15) };
        var url = $"https://api.duckduckgo.com/?q={Uri.EscapeDataString(query)}&format=json&no_html=1&t=ResearchAgent";
        try
        {
            var json = await http.GetStringAsync(url, cancellationToken);
            return json.Length > 4000 ? json[..4000] : json;
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    },
    "web_search",
    "Searches the web for information on a given query. Use varied queries to cover different aspects of the topic.");

var saveNoteTool = AIFunctionFactory.Create(
    [Description("Saves a research note capturing a key finding.")]
    (
        [Description("A concise research note with a key fact or finding")] string note) =>
    {
        notebook.Add(note);
        Console.ForegroundColor = ConsoleColor.DarkCyan;
        Console.WriteLine($"  📝 Note #{notebook.Count}: {Truncate(note, 80)}");
        Console.ResetColor();
        return $"Note saved ({notebook.Count} total).";
    },
    "save_note",
    "Records a research finding. Call this after each search to capture important facts before moving on.");

var viewNotesTool = AIFunctionFactory.Create(
    [Description("Returns all saved research notes for review before writing the summary.")]
    () => notebook.Count == 0
        ? "No notes saved yet. Use save_note to record findings."
        : notebook.Format(),
    "view_notes",
    "Reviews all saved notes. Call this before writing the final summary to ensure nothing is missed.");

// --- Create the ChatClientAgent ---
var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "An AI research assistant that searches the web and takes structured notes to produce summaries.",
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 4096,
            Tools = [searchTool, saveNoteTool, viewNotesTool],
        },
    });

// --- Get the topic from the user ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔬 Researching: {topic}\n");

// --- Run the agent ---
var response = await agent.RunAsync(
    $"""
    Research the following topic thoroughly and produce a comprehensive summary.

    Topic: {topic}

    Instructions:
    1. Perform at least 3 web searches using different queries to cover various aspects of the topic.
    2. After each search, save the most important findings as notes using save_note.
    3. Once you have gathered enough information, call view_notes to review everything.
    4. Finally, write a well-structured summary with sections, citing the key facts from your notes.
    """);

Console.WriteLine();
Console.WriteLine(response.Text);

// --- Print collected notes ---
Console.ForegroundColor = ConsoleColor.DarkGray;
Console.WriteLine($"\n--- Research Notes ({notebook.Count}) ---");
foreach (var (note, i) in notebook.Notes.Select((n, i) => (n, i)))
{
    Console.WriteLine($"  [{i + 1}] {note}");
}
Console.ResetColor();

// --- Helpers ---
static string Truncate(string text, int max)
    => text.Length <= max ? text : string.Concat(text.AsSpan(0, max), "…");

/// <summary>Thread-safe notebook for storing research findings.</summary>
sealed class ResearchNotebook
{
    private readonly List<string> _notes = [];
    private readonly Lock _lock = new();

    public int Count { get { lock (_lock) return _notes.Count; } }

    public IReadOnlyList<string> Notes { get { lock (_lock) return [.. _notes]; } }

    public void Add(string note)
    {
        lock (_lock) _notes.Add(note);
    }

    public string Format()
    {
        lock (_lock)
        {
            var sb = new StringBuilder();
            for (var i = 0; i < _notes.Count; i++)
                sb.AppendLine($"[{i + 1}] {_notes[i]}");
            return sb.ToString();
        }
    }
}

